import React from "react";
import { Link as LinkRouter } from "react-router-dom" 
import "../styles/cardsCities.css"

export default function CardsCities({ cardFilter }) {
    return(
        <div className="card-container">
        {cardFilter.map(city => (
            <div className="card" key={city._id}>
                <img className="image-card" src= {city.image} alt="hola" />
                <div>
                    <h2>{city.cityname}</h2>
                    <h3>{city.country}</h3>
                    <LinkRouter to={`citydetails/${city._id}`}>
                        See more
                    </LinkRouter>
                </div>
            </div>
        ))}
        </div>
    );
}
